mapper.select:
/* 사용자 영역 목록 조회 common.selectUserStrAreaList */
SELECT GROUP_CONCAT(STR_AREA_CD SEPARATOR ',') AS STR_AREA_LIST
FROM COM_ADMIN
WHERE COMP_ID = #{compId}
AND USER_ID = #{userId}

/* 메뉴 트리 목록 조회 common.selectMenuTreeList */ WITH RECURSIVE MENU_TREE AS ( SELECT M.MENU_ID , M.MENU_NAME , M.PARN_MENU_ID , M.MENU_LEVEL , M.MENU_PATH , M.IS_LEAF , M.SRC_PATH , M.ICON , M.SORT_ORD , M.USE_YN , M.DESCRIPTION , M.CREATE_DT , M.MODIFY_DT , CAST(LPAD(M.SORT_ORD,5,'0') AS CHAR(200)) AS SORT_PATH FROM TB_MENU M WHERE M.PARN_MENU_ID IS NULL AND M.USE_YN = 'Y'
UNION ALL
SELECT C.MENU_ID , C.MENU_NAME , C.PARN_MENU_ID , C.MENU_LEVEL , C.MENU_PATH , C.IS_LEAF , C.SRC_PATH , C.ICON , C.SORT_ORD , C.USE_YN , C.DESCRIPTION , C.CREATE_DT , C.MODIFY_DT , CONCAT(P.SORT_PATH,'/',LPAD(C.SORT_ORD,5,'0')) AS SORT_PATH FROM TB_MENU C JOIN MENU_TREE P ON C.PARN_MENU_ID = P.MENU_ID WHERE C.USE_YN = 'Y' ) SELECT MENU_ID , MENU_NAME , PARN_MENU_ID , MENU_LEVEL , MENU_PATH , IS_LEAF , SRC_PATH , ICON , SORT_ORD , USE_YN , DESCRIPTION FROM MENU_TREE ORDER BY SORT_PATH

/* 테이블 마지막 ID 조회 common.selectMaxId */
SELECT MAX(${idColumn})
FROM ${tableName}

/* 테이블 컬럼 MAX 정수값 조회 common.selectMaxInt */
SELECT IFNULL(MAX(${columnName}), 0)
FROM ${tableName}

/* 공유 카드 원본 CARD_ID 조회 common.selectCardIdByShareId */
SELECT CARD_ID
FROM TB_KNOW_CARD_SHARE
WHERE SHARE_ID = #{shareId}

mapper.update:
/* 지식 카드 맨 앞 등록을 위한 정렬 순서 증가 common.updateKnowledgeSortOrdForPrepend */
UPDATE TB_KNOW_CARD
SET SORT_ORD = SORT_ORD + 1
    , MODIFY_DT = NOW()
WHERE USER_ID = #{userId}
  AND CATEGORY_ID = #{categoryId}

/* 공유 카드 저장 정보 업데이트 common.updateKnowledgeShareSave */
UPDATE TB_KNOW_CARD_SHARE
SET SAVE_YN = 'Y'
    , SAVE_CARD_ID = #{saveCardId}
    , SAVE_CATEGORY_ID = #{saveCategoryId}
    , MODIFY_DT = NOW()
WHERE SHARE_ID = #{shareId}

/* 알림 읽음 처리 common.updateNotifyRead */
UPDATE TB_NOTIFY
SET READ_YN = 'Y'
    , READ_DT = NOW()
    , MODIFY_DT = NOW()
WHERE NOTIFY_ID = #{notifyId}
